#include <stdio.h>
int main() {
    int N, H;
    scanf("%d %d", &N, &H);
    int stacks[N];
    for (int i = 0; i < N; i++) {
        scanf("%d", &stacks[i]);
    }
    int cranePos = 0;
    int holdingBox = 0;
    int command;
    while (scanf("%d", &command) == 1) {
        if (command == 0) break;
        if (command == 1) {
            if (cranePos > 0) cranePos--;
        } else if (command == 2) {
            if (cranePos < N - 1) cranePos++;
        } else if (command == 3) {
            if (stacks[cranePos] > 0 && !holdingBox) {
                stacks[cranePos]--;
                holdingBox = 1;
            }
        } else if (command == 4) {
            if (holdingBox && stacks[cranePos] < H) {
                stacks[cranePos]++;
                holdingBox = 0;
            }
        }
    }
    for (int i = 0; i < N; i++) {
        printf("%d ", stacks[i]);
    }
    printf("\n");
    return 0;
}

