import java.util.Scanner;
public class Main {
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int N = sc.nextInt();
        int H = sc.nextInt();
        int[] stacks = new int[N];
        for (int i = 0; i < N; i++) {
            stacks[i] = sc.nextInt();
        }
        int cranePos = 0;
        int holdingBox = 0;
        int command;
        while (sc.hasNextInt()) {
            command = sc.nextInt();
            if (command == 0) break;
            if (command == 1) {
                if (cranePos > 0) cranePos--;
            } else if (command == 2) {
                if (cranePos < N - 1) cranePos++;
            } else if (command == 3) {
                if (stacks[cranePos] > 0 && holdingBox == 0) {
                    stacks[cranePos]--;
                    holdingBox = 1;
                }
            } else if (command == 4) {
                if (holdingBox == 1 && stacks[cranePos] < H) {
                    stacks[cranePos]++;
                    holdingBox = 0;
                }
            }
        }
        for (int i = 0; i < N; i++) {
            System.out.print(stacks[i] + " ");
        }
        System.out.println();
    }
}

